export function bpIcon(name, size, cls) {
  const p = BP_ICONS[name]; if (!p) return "";
  const s = size || 16;
  return `<svg class="${cls || ""}" data-icon="${name}" width="${s}" height="${s}" viewBox="0 0 16 16" role="img" fill="currentColor">${p.map((d) => `<path d="${d}" fill-rule="evenodd"></path>`).join("")}</svg>`;
}

